# -*- coding: utf-8 -*-
# AUTO-GENERATED Phase-5.
GLOSSARY_ADD = [
    {"term": "Germination", "defn": "The process of a dormant seed taking up water, waking, and pushing out its first root and shoot.", "tags": ["reference"]},
    {"term": "Taproot (radicle)", "defn": "The first white root to emerge from a seed; it grows downward to anchor the plant and seek water.", "tags": ["reference"]},
    {"term": "Cotyledons", "defn": "The two rounded embryonic 'seed leaves' that appear first and feed the seedling from stored reserves.", "tags": ["reference"]},
    {"term": "True leaves", "defn": "The familiar serrated cannabis leaves that grow after the cotyledons; their arrival marks the start of feeding.", "tags": ["reference"]},
    {"term": "Seed coat", "defn": "The hard protective outer shell of the seed that guards the embryo until conditions are right to sprout.", "tags": ["reference"]},
    {"term": "Embryo", "defn": "The tiny living baby plant inside the seed, already containing a root, two cotyledons, and a shoot.", "tags": ["reference"]},
    {"term": "Viable / viability", "defn": "Whether a seed is alive and capable of sprouting; viability declines as seeds age or are stored poorly.", "tags": ["reference"]},
    {"term": "Germination rate", "defn": "The percentage of a batch of seeds that successfully sprout.", "tags": ["reference"]},
    {"term": "Feminised seed", "defn": "Seed bred to produce almost only female plants, removing the need to identify and remove males.", "tags": ["reference"]},
    {"term": "Regular seed", "defn": "Untreated seed that produces a roughly even mix of male and female plants.", "tags": ["reference"]},
    {"term": "Autoflower seed", "defn": "Seed with ruderalis genetics that flowers automatically after a few weeks regardless of light schedule.", "tags": ["reference"]},
    {"term": "Photoperiod plant", "defn": "A plant that only begins flowering when daily light drops to about 12 hours; regular and feminised seeds are photoperiod.", "tags": ["reference"]},
    {"term": "Cannabis ruderalis", "defn": "A hardy cannabis subspecies whose genetics give autoflowers their automatic, light-independent flowering.", "tags": ["reference"]},
    {"term": "Damping-off", "defn": "A fungal disease (Pythium, Fusarium, Rhizoctonia) that rots a seedling at the soil line, usually killing it.", "tags": ["reference"]},
    {"term": "Humidity dome", "defn": "A clear cover placed over seedlings to trap moisture and keep humidity high while roots are tiny.", "tags": ["reference"]},
    {"term": "Imbibition", "defn": "The initial swelling of a seed as it absorbs water, the first physical step of germination.", "tags": ["reference"]},
    {"term": "PAR (Photosynthetically Active Radiation)", "defn": "The 400-700 nm band of light that plants can use for photosynthesis. Lumens, lux, and watts do not measure PAR, which is why they are useless for judging a grow light.", "tags": ["reference"]},
    {"term": "PPFD (Photosynthetic Photon Flux Density)", "defn": "How many usable (PAR) photons land on one square meter each second, measured in micromoles per square meter per second (umol/m2/s). This is the 'how bright at the canopy' number, read with a quantum/PAR meter.", "tags": ["reference"]},
    {"term": "DLI (Daily Light Integral)", "defn": "The total PAR photons delivered to a surface over a full day, in moles per square meter per day (mol/m2/day). DLI = PPFD x seconds of light per day / 1,000,000. It is the dose that most directly drives yield.", "tags": ["reference"]},
    {"term": "Spectrum", "defn": "The mix of light colors (wavelengths) a fixture emits. Blue (400-500 nm) favors compact growth; red (600-700 nm) drives flowering and is the most photosynthetically efficient band.", "tags": ["reference"]},
    {"term": "Kelvin (K) / color temperature", "defn": "A shorthand for the color mix of a white LED. Higher Kelvin (4000-6500K) is bluer and veg-leaning; lower Kelvin (3000-3500K) is redder and flower-leaning.", "tags": ["reference"]},
    {"term": "Efficacy (umol/J)", "defn": "How many usable PAR photons a fixture produces per joule of electricity. The key efficiency number when comparing lights: good LEDs are ~2.7-3.0 umol/J, HPS ~1.7-1.9, CMH ~1.3-1.9.", "tags": ["reference"]},
    {"term": "PPF (Photosynthetic Photon Flux)", "defn": "The total usable photons a fixture emits per second (umol/s), regardless of where they land. Divide PPF by wattage to get efficacy.", "tags": ["reference"]},
    {"term": "Phytochrome", "defn": "A plant pigment that senses red and far-red light and toggles between an active form (Pfr, 'it's day') and inactive form (Pr). It measures the length of the uninterrupted dark period and triggers the flowering signal.", "tags": ["reference"]},
    {"term": "Florigen", "defn": "The mobile flowering-signal protein made in the leaves once nights are long enough; it travels to the growing tips and reprograms them from making leaves to making buds.", "tags": ["reference"]},
    {"term": "Far-red", "defn": "Light around 700-750 nm, just past the PAR band. It is sensed by phytochrome, can speed the perceived onset of night, and adds some stem stretch; high doses can reduce bud density.", "tags": ["reference"]},
    {"term": "UV-B", "defn": "Ultraviolet light ~280-315 nm. Sometimes added in late flower in hopes of boosting trichomes/potency, but evidence is inconsistent and it poses real eye, skin, and plant-stress risks.", "tags": ["reference"]},
    {"term": "Inverse-square law", "defn": "Light intensity falls off with the square of distance: roughly doubling the fixture-to-canopy gap cuts PPFD by about 75%. This makes hanging height the coarse intensity control.", "tags": ["reference"]},
    {"term": "PPFD map / PAR map", "defn": "A manufacturer's grid showing PPFD across the coverage area at given hang heights. Use it as a starting point, then confirm with your own meter readings at canopy height.", "tags": ["reference"]},
    {"term": "Uniformity (min-to-average ratio)", "defn": "How evenly light covers the canopy, found by reading PPFD at nine grid points and dividing the lowest by the average. Above 0.75 is considered reasonably even.", "tags": ["reference"]},
    {"term": "Light saturation", "defn": "The point where a plant cannot use more light because CO2, water, nutrients, temperature, or genetics has become the limiting factor; beyond it, extra intensity adds cost and stress, not yield.", "tags": ["reference"]},
    {"term": "Light stress / bleaching", "defn": "Damage from too much intensity, showing as white/yellow bud tips directly under the fixture, upward-cupping 'taco' leaves, and faded color. The fix is to dim or raise the light, not to feed more.", "tags": ["reference"]},
    {"term": "Nutrient (essential element)", "defn": "One of the chemical elements a plant must absorb to grow normally; the major ones for cannabis are N, P, K, Ca, Mg and S, plus trace micronutrients like iron and zinc.", "tags": ["reference"]},
    {"term": "Macronutrient", "defn": "An element needed in large amounts: nitrogen (N), phosphorus (P), potassium (K), calcium (Ca), magnesium (Mg) and sulfur (S).", "tags": ["reference"]},
    {"term": "Micronutrient", "defn": "An element needed only in tiny amounts: iron (Fe), manganese (Mn), zinc (Zn), copper (Cu), boron (B) and molybdenum (Mo).", "tags": ["reference"]},
    {"term": "Mobile nutrient", "defn": "A nutrient the plant can withdraw from old leaves and resend to new growth when supply is short (N, P, K, Mg); its deficiency therefore shows on the oldest/lowest leaves first.", "tags": ["reference"]},
    {"term": "Immobile nutrient", "defn": "A nutrient that stays fixed where it was first deposited and cannot be relocated (Ca, S, Fe, Mn, Zn, B, Cu, Mo); its deficiency shows on the newest/top growth first.", "tags": ["reference"]},
    {"term": "Chlorosis", "defn": "Yellowing of leaf tissue caused by loss of green chlorophyll.", "tags": ["reference"]},
    {"term": "Interveinal chlorosis", "defn": "Yellowing between the leaf veins while the veins themselves stay green, a specific pattern seen with magnesium, iron and manganese problems.", "tags": ["reference"]},
    {"term": "Necrosis", "defn": "Dead, brown, dry or crispy leaf tissue, often at tips or edges.", "tags": ["reference"]},
    {"term": "Deficiency", "defn": "The plant is not getting enough of a nutrient, producing fading, yellowing and stunted growth.", "tags": ["reference"]},
    {"term": "Toxicity", "defn": "The plant has too much of a nutrient (or salts overall); typically dark, glossy, clawed leaves and burnt tips, the opposite look of a deficiency.", "tags": ["reference"]},
    {"term": "pH lockout", "defn": "A condition where a nutrient is present in the root zone but cannot be absorbed because root-zone pH is outside the range in which that nutrient stays dissolved.", "tags": ["reference"]},
    {"term": "PPM (parts per million)", "defn": "A unit expressing nutrient concentration in water, closely linked to EC; different conversion scales exist so the EC value is more universal.", "tags": ["reference"]},
    {"term": "Nutrient burn", "defn": "Tip and edge browning caused by feeding too strong a solution (excess salts), a form of toxicity.", "tags": ["reference"]},
    {"term": "The claw", "defn": "A downward hooking/curling of leaf tips, the classic sign of nitrogen toxicity (overfeeding).", "tags": ["reference"]},
    {"term": "Nutrient antagonism", "defn": "When an excess of one element blocks the uptake of another, e.g. too much potassium suppressing calcium and magnesium.", "tags": ["reference"]},
    {"term": "Flush", "defn": "Running plain or lightly fertilised, correctly pH'd water through the medium to wash out accumulated salts and reset the root zone.", "tags": ["reference"]},
    {"term": "Buffer (buffering)", "defn": "A medium's natural ability to resist pH change; soil buffers well, coco and hydroponics barely buffer at all, so they need tighter pH control.", "tags": ["reference"]},
    {"term": "Root zone", "defn": "The wet substrate immediately surrounding the roots, where nutrient and water uptake actually happens.", "tags": ["reference"]},
    {"term": "Nutrient lockout", "defn": "When nutrients are physically present but chemically bound into forms roots cannot absorb, usually because pH drifted out of range; looks like a deficiency.", "tags": ["reference"]},
    {"term": "Substrate (medium)", "defn": "The material roots grow in, e.g. coco coir, rockwool or water (hydro), or soil. Determines how much the root zone buffers pH.", "tags": ["reference"]},
    {"term": "Hydroponics", "defn": "Growing with roots in a nutrient water solution (or inert media fed by it) rather than soil; needs slightly acidic, closely managed pH.", "tags": ["reference"]},
    {"term": "Buffering capacity", "defn": "A medium or water's resistance to pH change. High buffering resists swings (soil); low buffering swings quickly (coco, hydro).", "tags": ["reference"]},
    {"term": "Alkalinity", "defn": "Water's built-in capacity to neutralise acid, mostly from bicarbonates, reported as ppm of calcium carbonate (CaCO3). Not the same as a high pH reading.", "tags": ["reference"]},
    {"term": "Bicarbonate (HCO3-)", "defn": "The main dissolved compound responsible for water alkalinity; it consumes added acid and pushes pH back up.", "tags": ["reference"]},
    {"term": "pH Down / pH Up", "defn": "Acid and base solutions used to adjust pH; Down is typically phosphoric acid, Up typically potassium hydroxide.", "tags": ["reference"]},
    {"term": "Two-point calibration", "defn": "Calibrating a pH pen against two known buffers (usually pH 7.0 then 4.0) so it reads accurately across the working range.", "tags": ["reference"]},
    {"term": "Buffer solution", "defn": "A liquid of precisely known pH (e.g. 4.0, 7.0) used to calibrate a pH pen.", "tags": ["reference"]},
    {"term": "KCl storage solution", "defn": "Potassium chloride solution that keeps a pH probe tip hydrated; storing dry or in plain water permanently damages the probe.", "tags": ["reference"]},
    {"term": "Probe drift", "defn": "Gradual loss of accuracy in a pH probe over time; replace when drift exceeds about 0.2 pH between calibrations.", "tags": ["reference"]},
    {"term": "Flip (12/12)", "defn": "Switching the grow-light timer to 12 hours on and 12 hours off, the change that triggers flowering in photoperiod plants.", "tags": ["reference"]},
    {"term": "Stretch", "defn": "The rapid vertical growth in the first 2-3 weeks of flower, where a plant can nearly double in height before settling into bud production.", "tags": ["reference"]},
    {"term": "Pistil", "defn": "A fine hair emerging from a bud site; white when young and darkening to orange/brown as the plant ripens. A rough, not definitive, harvest cue.", "tags": ["reference"]},
    {"term": "Trichome", "defn": "A microscopic resin gland coating the buds that holds most of the THC and aroma; its color (clear, milky, amber) is the primary harvest signal.", "tags": ["reference"]},
    {"term": "Calyx", "defn": "A single teardrop-shaped floral pod; many calyxes stacking together build a bud.", "tags": ["reference"]},
    {"term": "Cola", "defn": "A large, dense cluster of buds formed along a main stem, usually the topmost and best-developed flowers.", "tags": ["reference"]},
    {"term": "Bud set", "defn": "The point around weeks 3-4 when scattered pistils organise into defined, growing budlets.", "tags": ["reference"]},
    {"term": "Bulking", "defn": "The mid-flower phase (roughly weeks 5-7) when buds gain mass fastest.", "tags": ["reference"]},
    {"term": "Ripening", "defn": "The final phase when pistils darken, trichomes mature, and the plant moves stored nutrients into the buds before harvest.", "tags": ["reference"]},
    {"term": "Defoliation", "defn": "Selectively removing leaves to improve light penetration and airflow into the canopy.", "tags": ["reference"]},
    {"term": "Hermaphroditism (hermie)", "defn": "When a stressed female plant produces male parts and pollinates itself, seeding the buds; often caused by light leaks in the dark period.", "tags": ["reference"]},
    {"term": "Bud rot (botrytis)", "defn": "A grey mould that attacks dense buds in humid conditions, a major late-flower risk that drives the push to lower humidity.", "tags": ["reference"]},
    {"term": "IPM (Integrated Pest Management)", "defn": "A layered pest strategy combining prevention, monitoring, biological controls and targeted treatments rather than routine calendar spraying. This guide identifies the pests; the IPM SOP is the decision process.", "tags": ["reference"]},
    {"term": "Biocontrol / beneficial", "defn": "A living organism released to suppress a pest, a predatory mite, a parasitoid wasp, or a microbe such as a fungus or bacterium.", "tags": ["reference"]},
    {"term": "Preventative vs curative", "defn": "A preventative agent is established before pests arrive and persists on alternative food; a curative agent is released to knock down an active, growing outbreak.", "tags": ["reference"]},
    {"term": "Life cycle / generation time", "defn": "The time from egg to egg-laying adult. In warm dry rooms this drops below a week for spider mites, which is why infestations explode.", "tags": ["reference"]},
    {"term": "Stippling", "defn": "Fine pale speckling on leaves caused by sap-sucking pests piercing individual cells, classic for spider mites and thrips.", "tags": ["reference"]},
    {"term": "Honeydew", "defn": "Sticky sugary excretion from aphids and whitefly that coats leaves and grows black sooty mould.", "tags": ["reference"]},
    {"term": "Loupe / scope", "defn": "Magnifiers for inspection, a 30x hand loupe finds spider mites; russet and broad mites need 60-100x magnification.", "tags": ["reference"]},
    {"term": "Parasitoid wasp", "defn": "A tiny non-stinging wasp (e.g. Aphidius, Encarsia) that lays eggs in a host pest, killing it as the larva develops; key for aphids and whitefly.", "tags": ["reference"]},
    {"term": "Bti / Btk", "defn": "Strains of the soil bacterium Bacillus thuringiensis, israelensis (Bti) kills fungus-gnat larvae and kurstaki (Btk) kills caterpillars, both only when the pest ingests them.", "tags": ["reference"]},
    {"term": "Entomopathogenic nematodes", "defn": "Microscopic worms (e.g. Steinernema feltiae) drenched into the medium to parasitise and kill fungus-gnat larvae.", "tags": ["reference"]},
    {"term": "PPM / TDS", "defn": "Parts per million / total dissolved solids: the combined weight of everything dissolved in water. PPM meters convert from EC using a 500 or 700 scale, so readings can differ between meters.", "tags": ["reference"]},
    {"term": "Carbonate / bicarbonate", "defn": "The dissolved compounds (CO3 and HCO3) responsible for alkalinity. They neutralize added acid and can lock up calcium and magnesium when in excess.", "tags": ["reference"]},
    {"term": "Hardness", "defn": "The amount of dissolved calcium and magnesium in water, reported as ppm CaCO3 or grains per gallon (1 GPG = 17.1 mg/L). Soft water is under ~1 GPG; very hard is over ~10.5 GPG.", "tags": ["reference"]},
    {"term": "Chlorine", "defn": "A common municipal disinfectant that off-gasses from standing, aerated water in about 24 hours. Can damage root tips and beneficial microbes at low concentrations.", "tags": ["reference"]},
    {"term": "Chloramine", "defn": "A more stable chlorine-ammonia disinfectant that does NOT off-gas from standing water and requires a catalytic carbon filter or reverse osmosis to remove.", "tags": ["reference"]},
    {"term": "Reverse osmosis (RO)", "defn": "Filtration that forces water through a semipermeable membrane, stripping most dissolved minerals to leave near-zero PPM (typically 0-10 ppm TDS) water as a blank canvas.", "tags": ["reference"]},
    {"term": "Build back", "defn": "The practice of re-adding minerals (usually a CalMag supplement plus base nutrients) to mineral-stripped RO or rainwater, since the plant still needs calcium and magnesium and some buffer.", "tags": ["reference"]},
    {"term": "CalMag", "defn": "A calcium-and-magnesium (often with iron) supplement added to low-mineral water like RO, rain, or very soft tap to prevent calcium/magnesium deficiency.", "tags": ["reference"]},
    {"term": "Dissolved oxygen (DO)", "defn": "The amount of oxygen dissolved in water, which roots need. It falls as water warms (about 5-6 ppm at 20 C down to 3-4 ppm at 26 C), and low DO encourages root disease.", "tags": ["reference"]},
    {"term": "Sodium (Na)", "defn": "A non-nutrient salt sometimes high in well or coastal water. Elevated sodium competes with nutrient uptake and is a key reason to choose RO.", "tags": ["reference"]},
    {"term": "Substrate (growing medium)", "defn": "The material a plant's roots grow in; it holds the plant up and stores water, air, and dissolved nutrients.", "tags": ["reference"]},
    {"term": "Water-holding capacity", "defn": "The share of a medium's pore space that retains water after it has drained, expressed as a percentage by volume.", "tags": ["reference"]},
    {"term": "Air-filled porosity", "defn": "The share of a medium's pore space that holds air right after draining; it trades off directly against water-holding capacity.", "tags": ["reference"]},
    {"term": "Total porosity", "defn": "The total fraction of a medium that is open pore space (air plus water) rather than solid material.", "tags": ["reference"]},
    {"term": "CEC (cation exchange capacity)", "defn": "How strongly a medium grabs and holds positively-charged nutrient ions (in meq/100g); high CEC means more buffering of feed mistakes.", "tags": ["reference"]},
    {"term": "Buffering", "defn": "A medium's ability to absorb your errors in pH or nutrient strength so the roots see a steadier environment.", "tags": ["reference"]},
    {"term": "Rockwool (stonewool)", "defn": "Spun molten-rock fiber; inert, free-draining, holds lots of water with little buffering; alkaline until pre-soaked.", "tags": ["reference"]},
    {"term": "Peat", "defn": "Partially-decomposed bog moss; the airy, acidic, high-CEC base of most bagged soil mixes.", "tags": ["reference"]},
    {"term": "Living soil (ROLS)", "defn": "A microbe-rich organic soil bed (recycled organic living soil) that self-buffers pH and feeds plants via biology; water-only and reusable indefinitely.", "tags": ["reference"]},
    {"term": "DWC (deep water culture)", "defn": "Hydroponics where roots hang in oxygenated nutrient water with no solid medium; oxygen comes from an air pump.", "tags": ["reference"]},
    {"term": "Pre-buffering", "defn": "Soaking rinsed coco in a calcium-magnesium solution so its exchange sites stop stripping Ca/Mg from your feed.", "tags": ["reference"]},
    {"term": "Cal-mag", "defn": "A calcium and magnesium supplement; essential when running coco to prevent the deficiency caused by coco's CEC.", "tags": ["reference"]},
    {"term": "Inert medium", "defn": "A substrate (like rockwool) that holds no nutrients of its own, so the plant gets exactly what you feed and nothing else.", "tags": ["reference"]},
    {"term": "Pythium", "defn": "A water-mould pathogen that causes root rot, multiplying fast in warm (>23C) low-oxygen reservoirs.", "tags": ["reference"]},
]
